let p = msg.payload;
if (typeof p === 'string') {
  try { p = JSON.parse(p); } catch (e) { p = {}; }
}
if (!p || typeof p !== 'object') p = {};
if (p.payload && typeof p.payload === 'object') p = p.payload;
const nowIso = new Date().toISOString();
const presence = {
  received_at: nowIso,
  reason: p.reason || 'unknown',
  ip: p.ip || '',
  host: p.host || '',
  fw: p.fw || '',
  fw_full: p.fw_full || '',
  boot_id: p.boot_id || '',
  running_partition: p.running_partition || '',
  wifi_ssid: p.wifi_ssid || '',
  rssi: Number.isFinite(p.rssi) ? p.rssi : (p.rssi ?? null),
  rome_time: p.rome_time || ''
};
flow.set('esp32_presence', presence);
const fileMsg = { filename: '/data/esp32-power-console-last.json', payload: JSON.stringify(presence, null, 2) };
const notifyChatId = String(env.get('TELEGRAM_NOTIFY_CHAT_ID') || env.get('TELEGRAM_ALLOWED_CHAT_ID') || '').trim();
const shouldNotify = !!notifyChatId && (presence.reason === 'boot' || presence.reason === 'wifi_reconnected');
let notifyMsg = null;
if (shouldNotify) {
  let text = 'ESP32 Power Console';
  text += presence.reason === 'boot' ? '\nBoot completato.' : '\nWiFi riconnesso.';
  text += `\nIP: ${presence.ip || 'sconosciuto'}`;
  if (presence.host) text += `\nHOST: ${presence.host}`;
  if (presence.fw) text += `\nFW: ${presence.fw}`;
  if (presence.boot_id) text += `\nBOOT: ${presence.boot_id}`;
  if (presence.running_partition) text += `\nSlot: ${presence.running_partition}`;
  if (presence.wifi_ssid) text += `\nWiFi: ${presence.wifi_ssid}`;
  if (presence.rssi !== null && presence.rssi !== undefined) text += `\nRSSI: ${presence.rssi} dBm`;
  if (presence.rome_time) text += `\nOra board: ${presence.rome_time}`;
  notifyMsg = { payload: { chatId: notifyChatId, type: 'message', content: text } };
}
msg.payload = { ok: true, stored: true, ip: presence.ip, boot_id: presence.boot_id, reason: presence.reason, notify: shouldNotify };
return [msg, fileMsg, notifyMsg];

const presence = flow.get('esp32_presence') || {};
const fallback = String(env.get('ESP32_FALLBACK_URL') || '').trim();
let base = '';
if (presence.ip) base = `http://${presence.ip}`;
else if (fallback) base = fallback;
if (!base) return null;
msg.method = 'GET';
msg.url = `${base}/api/status`;
msg.headers = { Accept: 'application/json' };
msg.timeout = 5000;
return msg;

const p = msg.payload || {};
const status = {
  fetched_at: new Date().toISOString(),
  reachable: true,
  ip: p.ip || '',
  fw_version: p.fw_version || '',
  fw_full: p.fw_full || '',
  boot_id: p.boot_id || '',
  running_partition: p.running_partition || '',
  wifi_connected: !!p.wifi_connected,
  wifi_ssid: p.wifi_ssid || '',
  rssi: p.rssi ?? null,
  mode: p.mode || '',
  uptime_s: p.uptime_s ?? 0,
  rome_time: p.rome_time || '',
  raw: p
};
flow.set('esp32_status', status);
msg.filename = '/data/esp32-power-console-status.json';
msg.payload = JSON.stringify(status, null, 2);
return msg;

const allowed = String(env.get('TELEGRAM_ALLOWED_CHAT_ID') || '').trim();
const chatId = String(
  msg.chatId ??
  msg.payload?.chatId ??
  msg.originalMessage?.chat?.id ??
  msg.originalMessage?.from?.id ??
  ''
).trim();
if (!chatId) return null;
if (allowed && chatId !== allowed) {
  return [null, null, null, null, { payload: { chatId, type: 'message', content: 'Chat non autorizzata.' } }];
}
const rawText = String(
  msg.payload?.content ??
  msg.originalMessage?.text ??
  msg.originalMessage?.caption ??
  msg.payload?.text ??
  ''
).trim();
const firstToken = rawText.split(/\s+/)[0].toLowerCase();
const cmd = firstToken.replace(/@[^\s]+$/, '');
msg.chatId = chatId;
msg.replyChatId = chatId;
msg.commandText = rawText;
if (cmd === '/ip') return [msg, null, null, null, null];
if (cmd === '/status') return [null, msg, null, null, null];
if (cmd === '/pulse' || cmd === '/accendi') { msg.commandAction = 'pulse'; return [null, null, msg, null, null]; }
if (cmd === '/force' || cmd === '/forceshutdown') { msg.commandAction = 'force'; return [null, null, null, msg, null]; }
return [null, null, null, null, { payload: { chatId, type: 'message', content: 'Comandi disponibili:\n/ip\n/status\n/pulse\n/force\n/help' } }];

const p = flow.get('esp32_presence') || {};
const s = flow.get('esp32_status') || {};
const fallback = String(env.get('ESP32_FALLBACK_URL') || '').trim();
const fallbackIp = fallback.replace(/^https?:\/\//, '').replace(/\/$/, '');
const ip = p.ip || s.ip || fallbackIp || 'sconosciuto';
let text = 'ESP32 Power Console';
text += `\nIP: ${ip}`;
if (p.host) text += `\nHOST: ${p.host}`;
if (p.reason) text += `\nEvento: ${p.reason}`;
if (p.received_at) text += `\nUltimo report: ${p.received_at}`;
if (s.fetched_at) text += `\nUltimo keepalive: ${s.fetched_at}`;
if (s.uptime_s !== undefined) text += `\nUptime cache: ${s.uptime_s}s`;
msg.payload = { chatId: msg.chatId, type: 'message', content: text };
return msg;

const s = flow.get('esp32_status') || {};
const p = flow.get('esp32_presence') || {};
let text = 'ESP32 status (cache)';
if (s.fetched_at) text += `\nAggiornato: ${s.fetched_at}`;
else text += '\nAggiornato: nessun keepalive ancora disponibile';
text += `\nIP: ${s.ip || p.ip || 'sconosciuto'}`;
if (s.fw_version) text += `\nFW: ${s.fw_version}`;
if (s.boot_id) text += `\nBOOT: ${s.boot_id}`;
if (s.mode) text += `\nMODE: ${s.mode}`;
if (s.wifi_connected !== undefined) text += `\nWiFi: ${s.wifi_connected ? 'connesso' : 'non connesso'}`;
if (s.rssi !== undefined && s.rssi !== null) text += `\nRSSI: ${s.rssi} dBm`;
if (s.uptime_s !== undefined) text += `\nUptime: ${s.uptime_s}s`;
msg.payload = { chatId: msg.chatId, type: 'message', content: text };
return msg;

const presence = flow.get('esp32_presence') || {};
const fallback = String(env.get('ESP32_FALLBACK_URL') || '').trim();
const replyChatId = String(msg.replyChatId || msg.chatId || '').trim();
const dryRun = /^(1|true|yes|on)$/i.test(String(env.get('ESP32_COMMAND_DRY_RUN') || '').trim());
let base = '';
if (presence.ip) base = `http://${presence.ip}`;
else if (fallback) base = fallback;
msg.replyChatId = replyChatId;
msg.commandAction = 'pulse';
flow.set('esp32_last_command_meta', { chatId: replyChatId, action: 'pulse', at: Date.now() });
if (dryRun) {
  msg.payload = { chatId: replyChatId, type: 'message', content: 'DRY-RUN: /pulse riconosciuto. Nessun comando inviato alla board.' };
  return [null, msg];
}
if (!base) {
  msg.payload = { chatId: replyChatId, type: 'message', content: 'Nessun IP disponibile per la board.' };
  return [null, msg];
}
msg.method = 'GET';
msg.url = `${base}/api/pc/pulse`;
msg.headers = { Accept: 'application/json' };
msg.timeout = 5000;
return [msg, null];

const chatId = String(msg.replyChatId || msg.chatId || msg.originalMessage?.chat?.id || '').trim();
if (!chatId) return null;
const p = msg.payload;
let text = '';
if (p && typeof p === 'object') {
  if (p.ok === true) text = `Pulse inviato (${p.pulse_ms || '?'} ms)`;
  else if (p.error) text = `Pulse KO: ${p.error}`;
  else if (msg.statusCode >= 400) text = `Pulse KO: HTTP ${msg.statusCode}`;
}
if (!text && typeof p === 'string' && p.trim()) text = `Pulse KO: ${p}`;
if (!text) text = 'Pulse KO: errore sconosciuto';
msg.payload = { chatId, type: 'message', content: text };
return msg;

const presence = flow.get('esp32_presence') || {};
const fallback = String(env.get('ESP32_FALLBACK_URL') || '').trim();
const replyChatId = String(msg.replyChatId || msg.chatId || '').trim();
const dryRun = /^(1|true|yes|on)$/i.test(String(env.get('ESP32_COMMAND_DRY_RUN') || '').trim());
let base = '';
if (presence.ip) base = `http://${presence.ip}`;
else if (fallback) base = fallback;
msg.replyChatId = replyChatId;
msg.commandAction = 'force';
flow.set('esp32_last_command_meta', { chatId: replyChatId, action: 'force', at: Date.now() });
if (dryRun) {
  msg.payload = { chatId: replyChatId, type: 'message', content: 'DRY-RUN: /force riconosciuto. Nessun comando inviato alla board.' };
  return [null, msg];
}
if (!base) {
  msg.payload = { chatId: replyChatId, type: 'message', content: 'Nessun IP disponibile per la board.' };
  return [null, msg];
}
msg.method = 'GET';
msg.url = `${base}/api/pc/forceshutdown`;
msg.headers = { Accept: 'application/json' };
msg.timeout = 5000;
return [msg, null];

const chatId = String(msg.replyChatId || msg.chatId || msg.originalMessage?.chat?.id || '').trim();
if (!chatId) return null;
const p = msg.payload;
let text = '';
if (p && typeof p === 'object') {
  if (p.ok === true) text = `Force shutdown inviato (${p.pulse_ms || '?'} ms)`;
  else if (p.error) text = `Force shutdown KO: ${p.error}`;
  else if (msg.statusCode >= 400) text = `Force shutdown KO: HTTP ${msg.statusCode}`;
}
if (!text && typeof p === 'string' && p.trim()) text = `Force shutdown KO: ${p}`;
if (!text) text = 'Force shutdown KO: errore sconosciuto';
msg.payload = { chatId, type: 'message', content: text };
return msg;

const lastMeta = flow.get('esp32_last_command_meta') || {};
const chatId = String(msg.replyChatId ?? msg.chatId ?? msg.error?.source?.msg?.replyChatId ?? msg.error?.source?.msg?.chatId ?? lastMeta.chatId ?? '').trim();
if (!chatId) return null;
const action = String(msg.commandAction ?? msg.error?.source?.msg?.commandAction ?? lastMeta.action ?? 'request').toLowerCase();
const label = action === 'force' ? 'Force shutdown' : (action === 'pulse' ? 'Pulse' : 'Richiesta');
const err = msg.error?.message || msg.payload?.error || 'request failed';
msg.payload = { chatId, type: 'message', content: `${label} KO: ${err}` };
return msg;
